// Colors below were migrated from saved paint into code via api.paint.*
// (the model is now self-colouring; see /ai/colors.md). Edit colours here.
const __pwModel = (() => {
const { Manifold, CrossSection, label, round, geom } = api;

// Helper: axis-aligned box from min/max corners
function box(min, max) {
  const s = [max[0] - min[0], max[1] - min[1], max[2] - min[2]];
  const c = [(min[0] + max[0]) / 2, (min[1] + max[1]) / 2, (min[2] + max[2]) / 2];
  return Manifold.cube(s, true).translate(c);
}

// Main 16-unit cube body
const body = Manifold.cube([16, 16, 16], true);

// === HEART SHAPE ===
// The canonical Companion Cube heart is a smooth rounded outline, not pixel
// art. Previously this was raised cuboids on a 5x5 pixel grid, which reads as
// a stair-stepped silhouette. Instead, sketch one coarse heart control
// polygon (in content-axis `u` / vertical `z`) and let `geom.smooth` (Chaikin
// corner-cutting) round it into a smooth curve, then extrude to the same
// 1.2-unit protrusion depth (0.7 out + 0.5 overlap) the original used.
// (`api.round` on the raised boxes was considered first, but its
// morphological open/close would erase any feature thinner than 2x the
// radius — and the 1.2-unit-thick heart slab can't take a radius big enough
// to smooth 1-unit pixel steps without eroding the whole relief away. A
// smooth outline authored directly in 2D sidesteps that thickness limit.)
const heartProfile = [
  [0, -5.5],     // bottom point
  [2.2, -3.2],
  [4.2, -0.5],
  [5, 2],
  [4.6, 3.8],
  [3, 5],        // right lobe peak
  [1.3, 4.0],
  [0, 3.0],      // cleft dip between lobes
  [-1.3, 4.0],
  [-3, 5],       // left lobe peak
  [-4.6, 3.8],
  [-5, 2],
  [-4.2, -0.5],
  [-2.2, -3.2],
];
const heartThickness = 1.2; // 0.7 protrusion + 0.5 overlap into body, same as original

function heartPanel() {
  const cs = geom.smooth(heartProfile, { iterations: 3, kernel: 'chaikin', closed: true });
  return cs.extrude(heartThickness); // local: X=u(content), Y=z(vertical), Z=0..thickness(protrusion)
}

// Reorient the flat panel so its extrusion axis points along -Y (front-face
// protrusion), content axis along X, vertical axis along Z.
function frontOriented() {
  return heartPanel().rotate([90, 0, 0]); // -> X=u, Y=-e in [-thickness,0], Z=z
}
// Same, but with the extrusion axis pointing along +X (right-face protrusion).
function rightOriented() {
  return frontOriented().rotate([0, 0, 90]); // -> X=e in [0,thickness], Y=u, Z=z
}

// Front face heart (protrudes toward -Y): Y lands in [-8.7, -7.5]
const heartFront = frontOriented().translate([0, -7.5, 0]);
// Back face heart (protrudes toward +Y): mirror Y only, Y lands in [7.5, 8.7]
const heartBack = frontOriented().mirror([0, 1, 0]).translate([0, 7.5, 0]);
// Right face heart (protrudes toward +X): X lands in [7.5, 8.7]
const heartRight = rightOriented().translate([7.5, 0, 0]);
// Left face heart (protrudes toward -X): mirror X only, X lands in [-8.7, -7.5]
const heartLeft = rightOriented().mirror([1, 0, 0]).translate([-7.5, 0, 0]);

const hearts = heartFront.add(heartBack).add(heartLeft).add(heartRight);

// === EDGE BARS ===
// Raised bars along each of the 12 cube edges, 1.5 wide × 1 tall, full length
// 4 vertical edges (along Z)
const ev = 1.5; // edge bar half-width
const et = 1.0; // edge bar protrusion thickness
const eL = 16; // full cube edge length

// Corner positions at ±8, bar spans full length of edge
// Vertical edges — run along Z
function vEdgeBar(sx, sy) {
  // Centered on the corner at (sx*8, sy*8), runs z = -8..8
  return box([sx * 8 - et, sy * 8 - et, -8], [sx * 8 + et, sy * 8 + et, 8]);
}

// Horizontal edges along X
function hxEdgeBar(sy, sz) {
  return box([-8, sy * 8 - et, sz * 8 - et], [8, sy * 8 + et, sz * 8 + et]);
}

// Horizontal edges along Y
function hyEdgeBar(sx, sz) {
  return box([sx * 8 - et, -8, sz * 8 - et], [sx * 8 + et, 8, sz * 8 + et]);
}

const edgeBarsSharp =
  // 4 vertical edges
  vEdgeBar(-1, -1).add(vEdgeBar(1, -1)).add(vEdgeBar(-1, 1)).add(vEdgeBar(1, 1))
  // 4 edges along X (top and bottom)
  .add(hxEdgeBar(-1, -1)).add(hxEdgeBar(1, -1))
  .add(hxEdgeBar(-1, 1)).add(hxEdgeBar(1, 1))
  // 4 edges along Y (front/back at top and bottom)
  .add(hyEdgeBar(-1, -1)).add(hyEdgeBar(1, -1))
  .add(hyEdgeBar(-1, 1)).add(hyEdgeBar(1, 1));

// Soften the knife-sharp frame/corner-cap edges. The bar cross-section is
// 2*et = 2 units, so the radius must stay well under 1 (2*radius < thickness)
// or api.round's morphological open/close would erode the bars away.
// round() remeshes and drops labels, so it must run BEFORE label() below.
const edgeBars = round(edgeBarsSharp, { radius: 0.45 });

return label(body, 'body')
  .add(label(hearts, 'hearts'))
  .add(label(edgeBars, 'edges'));
})();
api.paint.label("body", [0.75, 0.78, 0.8]);
api.paint.label("hearts", [0.95, 0.45, 0.6]);
api.paint.label("edges", [0.5, 0.55, 0.62]);
return __pwModel;
